import bisect
class Solution:
    def longestObstacleCourseAtEachPosition(self, obstacles):
        # O(n^2) DP: ans[i] = 1 + max ans[j] for j<i with obstacles[j] <= obstacles[i]
        n = len(obstacles)
        dp = [1] * n
        res = []
        for i in range(n):
            best = 0
            for j in range(i):
                if obstacles[j] <= obstacles[i] and dp[j] > best:
                    best = dp[j]
            dp[i] = best + 1
            res.append(dp[i])
        return res

