import bisect
class Solution:
    def longestObstacleCourseAtEachPosition(self, obstacles):
        tails = []
        res = []
        for h in obstacles:
            idx = bisect.bisect_right(tails, h)
            if idx == len(tails):
                tails.append(h)
            else:
                tails[idx] = h
            res.append(idx + 1)
        return res

