var longestObstacleCourseAtEachPosition = function(obstacles) {
    const tails = [];
    const res = [];
    for (const h of obstacles) {
        let lo = 0, hi = tails.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (tails[mid] <= h) lo = mid + 1;
            else hi = mid;
        }
        if (lo === tails.length) tails.push(h);
        else tails[lo] = h;
        res.push(lo + 1);
    }
    return res;
};
